// Recebe o payload, exemplo: [{ "text": "oi" }]
const items = $input.all();

// Mapeia cada item mantendo a estrutura original
return items.map(item => {
  const textValue = item.json.text || "";

  return {
    json: {
      type: "human",
      content: textValue,
      additional_kwargs: {},
      response_metadata: {}
    }
  };
});

